async (params, browser) => {
  // Open Vivino
  await browser.open(`https://www.vivino.com/${params.wine_path}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*="vintageTitle"], .inner-page', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1, [class*="vintageTitle"], [class*="wineName"]')?.textContent?.trim() || ''; const winery = document.querySelector('[class*="winery"], a[href*="/wineries/"]')?.textContent?.trim() || ''; const rating = document.querySelector('[class*="averageValue"], [class*="averageRating"], [class*="rating"]')?.textContent?.trim() || ''; const ratingCount = document.querySelector('[class*="basedOn"], [class*="ratingCount"]')?.textContent?.trim() || ''; const price = document.querySelector('[class*="price"], [class*="amount"]')?.textContent?.trim() || ''; const region = document.querySelector('[class*="region"], [class*="country"], [class*="Location"]')?.textContent?.trim() || ''; const grape = document.querySelector('[class*="grape"], [class*="varietal"]')?.textContent?.trim() || ''; const desc = document.querySelector('[class*="description"], [class*="taste"]')?.textContent?.trim()?.slice(0, 500) || ''; return { name, winery, rating, ratingCount, price, region, grape, description: desc, url: window.location.href };`)

  return result
}
